#include<bits/stdc++.h>
#define ll long long 
using namespace std;
const int MAXN=1e5+5;
ll a[MAXN],u[MAXN],smin=0x7fffffff,T=0,F=0,d,ans=0,tmp;
int n;
int main(void){
	//freopen("road.in","r",stdin);
	//freopen("road.out","w",stdout);
	scanf("%d%lld",&n,&d);
	for(int i=1;i<=n-1;++i)scanf("%lld",u+i);
	for(int i=1;i<=n;++i)scanf("%lld",a+i);
	for(int i=1;i<n;++i){
		smin=min(smin,a[i]),T+=u[i],tmp=F,F+=ceil((T-tmp)*1./d)*d,ans+=ceil((T-tmp)*1./d)*smin;
	}printf("%lld",ans);
	return false;
}
